function renderProspectResponsibleSummary(items,done){const cols=(state.journeyProspects.columns||[]).map(c=>text(c.nome||c.etapaId)).filter(Boolean),colorOf=stageColors(state.journeyProspects),map=new Map();const ensure=name=>{name=text(name)||'Sem responsável';if(!map.has(name))map.set(name,{name,total:0,stages:{}});return map.get(name);};items.forEach(x=>{const r=ensure(responsibleTextOf(x));r.total++;const s=text(prospectStageName(x))||'—';r.stages[s]=(r.stages[s]||0)+1;});const rows=[...map.values()].sort((a,b)=>b.total-a.total||a.name.localeCompare(b.name,'pt-BR')).slice(0,8);const host=$('#prospectResponsibleSummary');if(!host)return;if(!rows.length){host.innerHTML='<div class="empty-state">Nenhum responsável no filtro atual.</div>';return;}host.innerHTML=rows.map(r=>{const order=cols.slice();Object.keys(r.stages).forEach(s=>{if(!order.includes(s))order.push(s);});const present=order.filter(s=>r.stages[s]);const segs=present.map(s=>`<span style="width:${Math.round((r.stages[s]/r.total)*100)}%;background:${colorOf[s]||'#94A3B8'}"></span>`).join('');const legend=present.map(s=>`<span class="li"><span class="dot" style="background:${colorOf[s]||'#94A3B8'}"></span>${esc(s)}</span>`).join('');return `<div class="rep-card"><div class="rep-top"><span class="name">${esc(r.name)}</span><span class="total">${esc(r.total)} em pipeline</span></div><div class="stack-bar">${segs}</div><div class="rep-legend">${legend}</div></div>`;}).join('');}

