function renderContextFilters(){$$('[data-context-filters]').forEach(host=>{const scope=contextScopeForHost(host),current=currentContextLocal(scope),locals=localOptionValues(current,scope),pf=scope==='prospect'?prospectContextFiltersHtml():'',curveHtml=scope==='prospect'?'':`<label><span class="material-symbols-rounded">leaderboard</span><select data-context-curve><option value="">Todas as curvas (clientes)</option>${CURVE_OPTIONS.map(x=>`<option value="${esc(x)}" ${state.filters.contextCurve===x?'selected':''}>Curva ${esc(x)}</option>`).join('')}</select></label>`;host.innerHTML=`<label><span class="material-symbols-rounded">location_on</span><select data-context-local data-context-local-scope="${esc(scope)}"><option value="">Todos os locais</option>${locals.map(x=>`<option value="${esc(x)}" ${current===x?'selected':''}>${esc(x)}</option>`).join('')}</select></label>${pf}${curveHtml}`;});$$('[data-context-local]').forEach(sel=>sel.onchange=()=>{setContextLocal(sel.dataset.contextLocalScope||'crm',sel.value);rerenderContext();});$$('[data-context-curve]').forEach(sel=>sel.onchange=()=>{state.filters.contextCurve=sel.value;rerenderContext();});$$('[data-prospect-filter]').forEach(sel=>sel.onchange=()=>{state.filters[sel.dataset.prospectFilter]=sel.value;rerenderContext();});}
